var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"아하핫, 신기하네. 이쪽 세계는 대전 액션이 아니라 라인 배틀로 싸우는 거야?","JPN":"アハハッ、面白いね。こっちの世界は対戦アクションじゃなくて、ラインバトルで戦うの？","ENG":"Ah hah hah, this is interesting. Are line battles more popular here than one-on-one fights?","TWN":"哈哈哈，真是奇妙，這個世界的打法竟然不是對打模式，而是無差別攻擊法？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"태그 매치도 없이 모두가 한꺼번에 전투를 벌이다니, 정신없는 환경이군.","JPN":"タッグマッチもなしで全員一斉に戦闘するなんて、なかなか慌ただしい環境だな。","ENG":"They come at once, instead of taking turns. This is a complete mess!","TWN":"而且也不是輪流上，一次全衝上來，有點應付不來呢！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_DESPAIR"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L7_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"그러게? 이렇게 뒤엉켜 싸우니까 내 화려한 기술이 네 엉덩이에 가려서 잘 안 보이잖아?","JPN":"そうね。こんなハチャメチャな環境じゃ、私の華麗なスキルがあんたのケツに邪魔されて見えないんじゃない！","ENG":"I couldn't agree more. We're entangled in such a fray that I can't see anything because of your butt. Move it, will you?","TWN":"就是說啊，這樣打成一團，我華麗的招式都被你的大屁股擋住看不到啦！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"스나이퍼 클래스면 걸리적거리지 말고 뒤로 빠져라, 원숭이.","JPN":"スナイパークラスなら邪魔しないで後ろに下がっていろ、サル。","ENG":"Stop getting in my way and stay behind, Sniper monkey.","TWN":"身為狙擊手少在那邊扯後腿，退到後面啦，臭猴子！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"헹, 너야말로 서포터가 왜 앞에서 알짱대는 건데?","JPN":"は？　あんたこそサポートのくせに前線でウロチョロするんじゃないよ。","ENG":"Hah! You're a Supporter. What are you doing in front of everyone?","TWN":"哼！你才是咧！身為輔助，在前面晃來晃去幹嘛？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"쯧.","JPN":"ちっ。","ENG":"Hmpf!","TWN":"嘖嘖！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"우와앗! 침식체가 또 엄청나게 몰려오고 있어요!","JPN":"うわー！　ものすごい数の侵食体が再び押し寄せてきてます！","ENG":"Waaah! There's a whole bunch of them coming again!","TWN":"保安！侵蝕體可以這樣打完又來，打完又來的嗎！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"함선이 곧 파괴될 것 같은데 지금이라도 도망칠까요?","JPN":"艦船が破壊されそうですけど、手遅れになる前に逃げますか？","ENG":"The ship is all but destroyed. Should we run now?","TWN":"艦船好像快毀掉咧？要棄船逃命嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"상관없어. 우린 아직 멀쩡하니까. 그깟 함선 하나쯤 없어져도 이길 수 있다고.","JPN":"いや。私たちはまだ全然平気だし、艦船一隻くらい消えても勝てるだろ？","ENG":"Doesn't matter. We're fine. We don't need the ship to beat them.","TWN":"不用！我們還能打！就算少一艘艦船，我們還是打得贏！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"네? 그치만 함선이 파괴되면 저희도 자동으로 전멸인데요?","JPN":"え？　艦船が破壊されたら私たちも自動的に全滅になるんですよ？","ENG":"Huh? If the ship gets destroyed, we'll be wiped out automatically.","TWN":"不明白？艦船毀掉的話，等於我們自動全軍覆沒不是嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"뭐어? 말도 안 돼! 무슨 그런 순 억지 시스템이 다 있어?!","JPN":"はあ？　どういうことだ？　そんなめちゃくちゃなシステムが実在するの！？","ENG":"WHAT? That makes no sense! It's unfair!","TWN":"什麼？完全不合理！怎麼會有這麼蠢的系統？！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"확실히 말도 안 되긴 하네.","JPN":"確かにあり得ないことだ。","ENG":"It does make no sense.","TWN":"確實是很不合理。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"너 같이 다른 세계의 규칙도 숙지 못한 원숭이가 어떻게 우주 경찰이 된 거지?","JPN":"お前みたいな他の世界のルールも熟知できないサルがどうやって宇宙警察になれたんだ？","ENG":"Monkey, how did you become a space cop without learning the rules of different worlds?","TWN":"像你這種不熟悉其他世界規則的猴子，是怎麼當上宇宙警察的？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"멀쩡한 눈 가리고 면접 본 녀석한테 그런 소리 듣고 싶지 않거든?!","JPN":"健康極まりない目なのに眼帯して面接するやつにそんなこと言われてもね！","ENG":"You don't get to judge; you had your interview while covering a perfectly functioning eye!","TWN":"像你這種明明眼睛沒事，還硬要帶個眼罩面試的傢伙，應該沒資格說我吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"저기. 지금 저희끼리 싸울 때가 아니지 않나요? 침식체가 뭘 쏘려는 것 같은데요!","JPN":"あのー、今言い争いしている場合じゃないと思いますよ？　侵食体が何か撃ってきそうです！","ENG":"Hey, I don't think this is a good time for us to fight. That C.O. is about to fire something at us!","TWN":"我說，現在不是搞內鬨的時候吧！侵蝕體好像要發射什麼的樣子欸！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"늦었군…","JPN":"手遅れか……","ENG":"We're late.","TWN":"為時已晚…"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"아, 망했다.","JPN":"はあ、やっちまった。","ENG":"Oh, dang. We're doomed.","TWN":"哎呀，糟糕。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"응?","JPN":"あれ？","ENG":"Hm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"우리 살아 있잖아? 설마 빗나갔나?","JPN":"私たち生きてる……？　外した？","ENG":"We're still alive. Did it miss us?","TWN":"我們沒死欸？是射歪了嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"…아니.","JPN":"……違う。","ENG":"...No.","TWN":"…不。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"누가 침식체의 공격을 막아냈어.","JPN":"誰かが侵食体の攻撃を防いでくれた。","ENG":"Somebody deflected it.","TWN":"是有人擋下侵蝕體的攻勢。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_NPC_FOOLSDAY_QM","text":{"KOREA":"다들 괜찮은가?","JPN":"みんな、無事か？","ENG":"Is everyone okay?","TWN":"大家都沒事吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L43_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"당신은…?","JPN":"あなたは……？","ENG":"Who are you?","TWN":"你是…？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ESTAROSSA_NPC_FOOLSDAY_NAMED","text":{"KOREA":"나는 우주 평화수립 기사단의 그랜드 마스터 E.C다.","JPN":"私は宇宙平和樹立騎士団のグランドマスターE.Cだ。","ENG":"I'm Grand Master E.C., of the Universal Peace Establishment Knights.","TWN":"我是守護宇宙和平騎士團的團長 E.C。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_FOOLSDAY_NAMED","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_NPC_FOOLSDAY_NAMED","text":{"KOREA":"구원요청 신호를 받고 오게 됐어.","JPN":"救助要請の信号を受けて来た。","ENG":"I received your distress signal.","TWN":"我收到求救訊號，所以前來救援。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"엑?","JPN":"エク？","ENG":"Eck?","TWN":"有？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"익?","JPN":"イク？","ENG":"Eeck?","TWN":"嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_NPC_FOOLSDAY_NAMED","text":{"KOREA":"이니셜일 뿐이니 그렇게 붙여서 발음하지 말아주겠나?","JPN":"E.Cは普通にイニシャルだからそんなふうに呼ぶのはやめたまえ。","ENG":"It's pronounced ee-cee, not eck or eeck.","TWN":"話可以一次說完，不要亂斷句嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_FOOLSDAY_NAMED","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"우와아! 그 흠뻑 젖은 옷차림은 뭔가요? 장난 아닌 그림체로 장난 아닌 시추에이션!","JPN":"うわあ！　そのずぶ濡れの格好はどうしたんですか？　すごい絵柄にすごいシチュエーション！","ENG":"Whoa, why are you soaking wet? Your art style is really something! In a quite serious situation!","TWN":"哇賽！那身溼透的衣服是怎麼回事？不是在開玩笑的欸！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_FOOLSDAY_NAMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_NPC_FOOLSDAY_NAMED","text":{"KOREA":"이건… 훈련을 끝마치고 퇴근을 준비하던 중에 급히 호출을 받아서 오게 된 거다.","JPN":"これは……訓練が終わって上がろうとする際に急遽呼び出されたからだ。","ENG":"This... I'd just finished my training and was getting ready to leave for the day when I got your call.","TWN":"這個嗎…因為我訓練完準備要下班時，收到緊急求救訊號，所以才趕過來的。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_NPC_FOOLSDAY_NAMED","text":{"KOREA":"그렇게 빤히 바라보지 말아주겠나?","JPN":"そんなにジロジロみるのは控えてくれないか？","ENG":"Could you stop staring at me like that?","TWN":"你可以不要一直盯著我看嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_FOOLSDAY_NAMED","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"앗! 죄송합니다!","JPN":"あっ、すみません！","ENG":"Ah! Sorry!","TWN":"喔！對不起！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_FOOLSDAY_NAMED","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"구조대? 우린 그런 거 안 불렀는데?","JPN":"救助？　私たちはそんな要請はしていないけど？","ENG":"But whose call? We didn't make any calls.","TWN":"求救訊號？不是我們發的吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"배달부, 당신이 호출한 건가?","JPN":"配達員、お前が呼んだのか？","ENG":"Deliverywoman, did you make the call?","TWN":"外送員，是你發出的求救訊號嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"네? 저요? 기사단을요? 제가 아는 기사는 배달기사 밖에 없는데요?","JPN":"え？　私がですか？　騎士団を？　私の知り合いは同じ配達員しかいませんよ？","ENG":"Huh? Me? To the Knights? The only knights I know only exist in romance novels.","TWN":"我？怎麼可能？我只是認識機車騎士，不認識什麼騎士團欸？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_FOOLSDAY_NAMED","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_NPC_FOOLSDAY_NAMED","text":{"KOREA":"그렇다면 그 로봇 목소리는 역시 장난전화였나…?","JPN":"ならばあのロボットの声は誰かのイタズラだったのか……？","ENG":"So, that robotic voice I heard was just a prank call.","TWN":"意思是那通機器人聲音的電話是惡作劇嗎…？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"그런 모양이지. 보다시피 이쪽엔 로봇이 없거든.","JPN":"そうみたいね。見ての通り、ここにロボットはいないから。","ENG":"Probably. As you can see, none of us is a robot.","TWN":"應該是吧？這邊很明顯沒有機器人吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_NPC_FOOLSDAY_NAMED","text":{"KOREA":"그렇군.","JPN":"なるほど。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_NPC_FOOLSDAY_NAMED","text":{"KOREA":"하지만 그 신고 덕에 위기에 처한 그대들을 도울 수 있었어.","JPN":"しかしその信号のおかげで、ピンチだった君たちを助けることができた。","ENG":"But because of it, I came to help you.","TWN":"不過也因為那通惡作劇電話，我才能在你們危難之際拯救你們。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_FOOLSDAY_NAMED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_NPC_FOOLSDAY_NAMED","text":{"KOREA":"그러니 굳이 신고자가 누구인지 추궁할 필욘 없겠지.","JPN":"だから今ここでその者が誰なのか追及する必要はないだろう。","ENG":"It doesn't matter who really made that call.","TWN":"也就不需要再追究是何人所為。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"뜻하지 않게 신세를 졌군.","JPN":"偶然かもしれないが、世話になったな。","ENG":"We owe you one.","TWN":"結果欠你一個人情呢。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"답례라고 하긴 그렇지만 고기 좋아하나? 마침 회식 예정이거든.","JPN":"お礼というにはちょっとあれかもしれないが、肉は好きか？　ちょうどこの後パーティする予定でね。","ENG":"This may not be a proper way of thanking you, but do you like meat? We're about to have company dinner.","TWN":"這也不算是謝禮，不過你喜歡肉嗎？我們正好要聚餐。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_NPC_FOOLSDAY_NAMED","text":{"KOREA":"싫어하진 않는다.","JPN":"嫌いではない。","ENG":"I don't dislike it.","TWN":"是不討厭。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_FOOLSDAY_NAMED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_NPC_FOOLSDAY_NAMED","text":{"KOREA":"하지만 난 보다시피 퇴근 중에 서둘러 나온 입장이야. 이제 그만 돌아가봐야…","JPN":"しかしご覧のとおり、私は仕事上がりに急いで現場に来たわけで、そろそろ帰らねば……","ENG":"But as I told you, I was about to leave for the day. I should go back—","TWN":"不過我是準備下班到一半趕過來的，必須再回去一趟…"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_FOOLSDAY_NAMED","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"그쪽 동료 분들은 같이 합석할 의향이 있다는데?","JPN":"そっちの仲間たちは同席する意向があるように見えるよ？","ENG":"But your colleagues would love to come.","TWN":"可是你的同事好像很想參加欸？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>야호! 슈퍼 프라임 등급 우주 소고기로 회식이라니! 우리 단장님, 최고!</color>","JPN":"やった！　スーパープライムランク宇宙牛肉のパーティだ！　団長、サイコー！！","ENG":"Wee! Are we eating Super Prime-grade space beef? Captain, you're the best!","TWN":"呀呵！聚餐要吃頂級宇宙牛肉欸！團長真是讚！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L37_1","type":"dialog","speaker":"ESTAROSSA_NPC_FOOLSDAY_NAMED","text":{"KOREA":"음? 어느새 연락까지 한 거지?","JPN":"うん？　いつの間に我が騎士団に連絡したのだ？","ENG":"Huh? How did you get a hold of her?","TWN":"嗯？什麼時候打給他們的？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_FOOLSDAY_NAMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"앗, 저희 업체에 기사단 연락처가 있더라고요. 형사님이 가르쳐 달라고 부탁하시길래… 아하하…","JPN":"あ、うちの顧客リストに騎士団の連絡先がありました。刑事さんに教えてと頼まれて……アハハ……","ENG":"Ah, my company has your contact information. The cop asked me for it, so... Ah hah hah.","TWN":"剛好我們公司有騎士團的聯絡方式，警察大人請我告訴他們，所以就…呵呵呵…"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_FOOLSDAY_NAMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"걱정 마. 땀 때문에 불편하다면 샤워시설 정도는 제공해 줄 수 있어.","JPN":"心配するな。汗が気になるなら、シャワー室くらい提供できる。","ENG":"Don't worry. If you're worried about being sweaty, you can use our shower room.","TWN":"如果是因為流汗不方便，你放心，我們可以提供淋浴設備。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"아쉽게도 갈아입을 옷은 동물잠옷 정도 밖에 없지만.","JPN":"残念ながら予備の着替えは動物柄のパジャマしかないが。","ENG":"As for a change of clothes, though, we only have animal print PJs.","TWN":"只是，可以替換的衣服就只有動物造型的睡衣。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_NPC_FOOLSDAY_NAMED","text":{"KOREA":"펭귄도 있나?","JPN":"ペンギンもあるのか？","ENG":"Penguin, too?","TWN":"有企鵝造型的嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"그야 물론이지. 펭귄은 우리 경찰서 마스코트거든.","JPN":"もちろん。ペンギンはうちの署のマスコットなんだ。","ENG":"Of course. In fact, the penguin is our station's mascot.","TWN":"當然有！企鵝可是我們署裡的吉祥物呢！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_NPC_FOOLSDAY_NAMED","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_FOOLSDAY_NAMED","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_NPC_FOOLSDAY_NAMED","text":{"KOREA":"알겠다. 그렇게까지 성의를 보이는데 거절하는 것도 기사답지 못한 일이겠지.","JPN":"承知した。そこまで誠意を示してくれるなら、断り続けるのは騎士としてよろしくないだろう。","ENG":"Alright, if you insist, I'll accept your offer like the honorable knight I am.","TWN":"好吧，既然你們這麼有誠意地邀請，我再拒絕下去也不符合騎士的風範。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_FOOLSDAY_NAMED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"야호! 그럼 다 같이 맛있는 거 먹으러 가는 거죠?","JPN":"イエーイ！　それじゃあ、みんなで美味しいものを食べに行きましょう！","ENG":"Woohoo! Then, let's go have a feast!","TWN":"呀呵！那大家就一起去吃好吃的吧！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L1_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"넌 끼워준다고 안 했어.","JPN":"あんたはダメだよ。","ENG":"I didn't say you could come.","TWN":"我可沒邀請你。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"히잉…","JPN":"ふええ……","ENG":"Hnngg...","TWN":"嗚嗚…"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","text":{"KOREA":"당신 제법 실력이 좋던데, 우리 우주경찰에 지원한다면 고려는 해보지.","JPN":"お前はなかなかの腕前だったし、宇宙警察に志願するなら考えてやろう。","ENG":"You're pretty good at fighting. I'll let you in if you apply for a job with the Space Police.","TWN":"你的能力不錯，要是你願意報考宇宙警察，那我可以考慮讓你來吃烤肉。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOONPC_NPC_FOOLSDAY_NAMED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"앗! 할래요! 사실 우주경찰이 되는 거랑 슈퍼 프라임 등급 우주 소고기 먹는 건 전부 버킷리스트에 있는 것들이거든요!","JPN":"ホントですか？　やります！　実は宇宙警察になるのと、スーパープライムランク宇宙牛肉を食べるのも、全部「死ぬ前にやっておきたいリスト」に書いてあるんです！　","ENG":"Ah, I'll do it! In fact, becoming a space cop and eating Super Prime space beef are both on my bucket list!","TWN":"好！我願意！成為宇宙警察，和吃極品宇宙牛肉，都在我的人生必做清單當中呢！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L9_1","type":"dialog","speaker":"AMY_NPC_FOOLSDAY_NAMED","text":{"KOREA":"어쩔 수 없지. 대신 고기는 네가 구워라.","JPN":"しょうがないな。代わりに、肉はあんたが焼くんだよ。","ENG":"Alright, you're in. You'll grill the meat, though.","TWN":"就讓你來吧，不過你要負責烤喔！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"넵!","JPN":"はいっ！","ENG":"Yes, ma'am!","TWN":"好！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_NPC_FOOLSDAY_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"그렇게 외우주에서는 우주경찰과 우주기사 그리고 우주배달부가 만나 슈퍼 프라임 등급 우주 소고기로 때아닌 회식을 가졌다.","JPN":"そうして外宇宙では、宇宙警察と宇宙騎士、そして宇宙配達員が出会い、スーパープライムランクの宇宙牛肉でパーティをした。","ENG":"Like that, somewhere in the outer space, the space cops, space knights, and a space deliverywoman met and dined on Super Prime space beef.","TWN":"就這樣，宇宙警察、宇宙騎士團和宇宙配送員在外太空聚一起享用極品宇宙牛肉，好不熱鬧。"},"stage":{"bg":"BLACK","bgm":"OFFICE_COMMON_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"기사단장은 돌아가는 길에 동물잠옷을 선물로 받았다.","JPN":"騎士団長は帰る間際、動物柄のパジャマをプレゼントでもらった。","ENG":"The knight captain received animal pajamas as a gift at the end.","TWN":"騎士團長在回來的路上還收到動物睡衣當作禮物。"},"stage":{"bg":"BLACK","bgm":"OFFICE_COMMON_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"라라 예거는 우주경찰에 지원했지만, 1차 심사에서 청기백기를 통과하지 못해 떨어지고 만다.","JPN":"ララ・イェーガーは宇宙警察に志願したが、旗あげゲームを通過できず1次審査で落ちてしまった。","ENG":"Lara Jaeger applied for a space cop position, but failed the first test based on the blue-flag-and-white-flag game.","TWN":"拉拉·伊格雖然有報考宇宙警察，卻在第一關就不幸落馬。"},"stage":{"bg":"BLACK","bgm":"OFFICE_COMMON_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"그렇게, 이 우주의 평화는 오늘도 계속되고 있다.","JPN":"そうして、この宇宙の平和は今日も続いている。","ENG":"Just like that, the peace of the universe continues.","TWN":"今天宇宙的和平也將持續下去。"},"stage":{"bg":"BLACK","bgm":"OFFICE_COMMON_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"아마도.","JPN":"……おそらく。","ENG":"Maybe.","TWN":"應該吧。"},"stage":{"bg":"BLACK","bgm":"OFFICE_COMMON_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"}]`);export{e as default};